class OrderServiceClient:
    def __init__(self, base_url: str):
        self._client = AsyncClient(base_url=base_url, timeout=10.0)

    async def get_orders_for_user(self, user_id: UUID) -> list:
        response = await self._client.get("/api/v1/orders", params={"user_id": str(user_id)})
        response.raise_for_status()
        return response.json()

class MessagePublisher:
    def __init__(self, channel):
        self._channel = channel

    async def publish(self, event) -> None:
        exchange = await self._channel.get_exchange("events")
        message = aio_pika.Message(
            body=json.dumps({
                "type": "user.created",
                "data": {"user_id": str(event.user_id), "email": event.email},
                "occurred_at": event.occurred_at.isoformat(),
            }).encode(),
            content_type="application/json",
        )
        await exchange.publish(message, routing_key="user.created")
